VALUES
  ('elementary-d0d1b9a2-moex-00475', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', 'X1年8月1日甲公司持票據向銀行貼現，貼現率為6%。該票據為X1年6月1日所開6個月期，票面利 率2%，面額$500,000。甲公司貼現可得金額為何？', '["$454,900", "$479,400", "$494,900", "$519,400"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00476', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司採定期盤存制，X1年底計有2筆運送中進貨，其中一筆為起運點交貨$3,000，另一筆為目的地交貨 $2,000，甲公司皆未入帳亦未盤點到，則存貨錯誤對甲公司X1年淨利影響（不考慮所得稅之影響）為何？', '["不影響", "多計$1,000", "多計$3,000", "多計$5,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00477', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', 'X1年9月1日甲公司賒購一批商品$40,000，起運點交貨，運費$500，付款條件「?/10，n/30」，甲公司 於X1年9月10日支付80%貨款，其餘於X1年9月30日付清，該項進貨甲公司帳列存貨合計$39,380， 試問付款條件中「？」為何？', '["1.9375", "2", "3", "3.5"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00478', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司X1年度有關資料如下：進貨運費$15,000，進貨退出$60,000，銷貨運費$140,000，銷售費用$214,000， 期末存貨$50,000，倘若銷貨成本為銷售費用的4倍，則甲公司X1年度本期可供銷售商品成本為：', '["$914,000", "$856,000", "$951,000", "$906,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00479', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '臺灣公司今年初購入海島公司3年期的公司債，該債券的面額為$1,000,000，票面利率3%，約定每年的 1月5日付息一次。假設與該債券同信用等級的市場利率為5.01%，該公司債的公允價值為$945,273， 購入時另需支付交易成本$262。有關購入此筆公司債之敘述，下列何者正確？', '["臺灣公司對於該公司債所支付的交易成本一律作為當期費用", "臺灣公司須考量該債券的合約現金流量特性與經營模式以決定該公司債之會計處理", "臺灣公司購入該公司債是以溢價的方式取得", "臺灣公司對於該公司債所支付的交易成本一律作為資產成本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00480', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X5年初以成本$800,000購買乙公司股票，並分類為透過其他綜合損益按公允價值衡量之金融資 產，X5 年底該金融資產的公允價值為$885,000，有關此投資對甲公司 X5 年財務報表之影響，下列敘述 何者正確？', '["本期淨利增加$85,000", "本期淨利減少$85,000", "權益總額增加$85,000", "權益總額減少$85,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00481', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '非金融業之甲公司X1年11月1日以$50,000購買債務投資並分類為透過其他綜合損益按公允價值衡量金 融資產。X1年12月31日該投資公允價值為$45,800，甲公司判斷該債務工具原始認列後信用風險並未顯 著增加，僅評估12個月預期信用損失$1,530。下列敘述何者錯誤？（不考慮所得稅）', '["X1年度與該投資相關之預期信用減損損失$4,200", "X1年度與該投資相關之預期信用減損損失應列在營業外收入及費用", "X1年度綜合損益表中與該投資相關之其他綜合損失為$2,670", "X1年12月31日資產負債表中，透過其他綜合損益按公允價值衡量金融資產為$45,800"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00482', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X8年初以$100,000購入乙公司普通股股權20%。若乙公司X9年之本期淨利為$800,000，宣告 並發放之現金股利為$60,000，下列敘述何者必定正確？', '["甲公司應將乙公司編入合併財務報表", "若甲公司對乙公司之投資採權益法處理，甲公司對乙公司X9年之本期淨利無須作任何分錄", "若甲公司對乙公司之投資分類為透過損益按公允價值衡量之金融資產，乙公司宣告並發放現金股利 時，甲公司應認列透過損益按公允價值衡量之金融資產的評價利益$12,000", "若甲公司對乙公司之投資採權益法處理，乙公司宣告並發放現金股利時，甲公司應貸記採用權益法之 投資$12,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00483', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X1年1月1日以$900,000購買機器，經評估耐用年限10年，殘值$60,000，採直線法提列折舊 並以成本模式後續衡量。X4年1月1日支付$200,000增添機器零件使機器耐用年限增加2年，殘值改為 $20,000。若X5年1月1日另支付$9,000維修以維持機器正常使用，則該機器之X5年度折舊為：', '["$69,000", "$92,000", "$93,000", "$83,700"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00484', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '下列有關不動產、廠房及設備採重估價模式衡量之敘述，何者錯誤？', '["若資產過去未曾認列重估價損失或減損損失，則資產帳面金額因重估而增加時，應列為其他綜合損益", "重估價模式僅有在資產公允價值能可靠衡量時才能採用", "重估價資產之公允價值產生重大波動時即需重估", "同類別之不動產、廠房及設備項目可以選擇僅對部分項目進行重估價"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
